parameters.jsCode:
// Extraer la respuesta de Gemini
const geminiResponse = $input.first().json;
const text = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text ?? '{}';
const extractedData = $('Extraer datos').first().json;

let parsed;
try {
  parsed = JSON.parse(text);
} catch {
  parsed = {
    intent: 'unknown',
    response: 'No pude procesar tu mensaje. ¿Podrías reformularlo?',
    cardTitle: null,
    actions: []
  };
}

// Construir el payload para POST /api/agents/notify
const notifyPayload = {
  message: parsed.response || 'Procesado correctamente.',
  targetUserId: extractedData.senderId || null,
};

// Solo agregar card si hay título y acciones
if (parsed.cardTitle && parsed.actions && parsed.actions.length > 0) {
  notifyPayload.cardTitle = parsed.cardTitle;
  notifyPayload.actions = parsed.actions.map(a => ({
    label: a.label || 'Acción',
    actionType: a.actionType || 'custom',
    payload: a.payload || {},
    style: a.style || 'primary'
  }));
}

// Siempre agregar botón de dismiss si hay acciones
if (notifyPayload.actions && notifyPayload.actions.length > 0) {
  notifyPayload.actions.push({
    label: 'Descartar',
    actionType: 'dismiss',
    payload: {},
    style: 'secondary'
  });
}

return [{
  json: {
    notifyPayload,
    intent: parsed.intent,
    channelId: extractedData.channelId
  }
}];
